#ifndef KERNEL_H
#define KERNEL_H

#include <cuda_runtime.h>
#include <stdint.h>
#include <device_launch_parameters.h>

// Fixed vocabulary size for DeepSeek V3
#define VOCAB_SIZE 129280

// Kernel function declaration
__global__ void top_k_sampling_kernel(
    const float* __restrict__ probs,
    const int32_t* __restrict__ top_k,
    int64_t* __restrict__ samples,
    int32_t batch_size,
    int32_t vocab_size,
    unsigned long long seed
);

// Host function declaration
void launch_top_k_sampling(
    const float* probs,
    const int32_t* top_k,
    int64_t* samples,
    int32_t batch_size,
    int32_t vocab_size
);

#endif // KERNEL_H

#include "kernel.h"
#include <curand_kernel.h>
#include <device_launch_parameters.h>
#include <cstdio>

// Device function for swapping elements
__device__ __forceinline__ void swap(float* a, float* b, int32_t* ia, int32_t* ib) {
    float tmp_f = *a;
    *a = *b;
    *b = tmp_f;
    int32_t tmp_i = *ia;
    *ia = *ib;
    *ib = tmp_i;
}

// Device function for multinomial sampling using inverse transform
__device__ int64_t multinomial_sample(
    const float* probs,
    const int32_t* indices,
    int32_t k,
    curandStatePhilox4_32_10_t* state
) {
    float r = curand_uniform(state);

    // Cumulative sum and find sample
    float cumsum = 0.0f;
    int64_t sample_idx = indices[0];

    for (int i = 0; i < k; i++) {
        cumsum += probs[i];
        if (r < cumsum) {
            sample_idx = indices[i];
            break;
        }
    }

    return sample_idx;
}

// Device function to find top-k indices using selection sort
// Each thread processes a portion of the array
__device__ void find_top_k(
    const float* probs,
    const int32_t* indices,
    int32_t k,
    int32_t vocab_size,
    float* top_k_probs,
    int32_t* top_k_indices
) {
    // Copy first k elements
    for (int i = 0; i < k; i++) {
        top_k_probs[i] = probs[i];
        top_k_indices[i] = indices[i];
    }

    // Process remaining elements
    for (int i = k; i < vocab_size; i++) {
        float val = probs[i];
        int32_t idx = indices[i];

        // Find minimum in top-k
        int min_pos = 0;
        float min_val = top_k_probs[0];
        for (int j = 1; j < k; j++) {
            if (top_k_probs[j] < min_val) {
                min_val = top_k_probs[j];
                min_pos = j;
            }
        }

        // Replace if current value is larger
        if (val > min_val) {
            top_k_probs[min_pos] = val;
            top_k_indices[min_pos] = idx;
        }
    }

    // Sort top-k in descending order
    for (int i = 0; i < k - 1; i++) {
        for (int j = i + 1; j < k; j++) {
            if (top_k_probs[j] > top_k_probs[i]) {
                swap(&top_k_probs[i], &top_k_probs[j], 
                     &top_k_indices[i], &top_k_indices[j]);
            }
        }
    }
}

__global__ void top_k_sampling_kernel(
    const float* __restrict__ probs,
    const int32_t* __restrict__ top_k,
    int64_t* __restrict__ samples,
    int32_t batch_size,
    int32_t vocab_size,
    unsigned long long seed
) {
    int batch_idx = blockIdx.x;
    if (batch_idx >= batch_size) return;

    int k = top_k[batch_idx];

    // Validate k - if invalid, use full distribution
    if (k <= 0 || k >= vocab_size) {
        k = vocab_size;
    }

    // Use shared memory for top-k selection (much smaller than full vocab)
    extern __shared__ char shared_mem[];
    float* s_top_k_probs = (float*)shared_mem;
    int32_t* s_top_k_indices = (int32_t*)(shared_mem + k * sizeof(float));

    // Each thread processes a portion of the vocabulary
    int offset = batch_idx * vocab_size;
    int threads = blockDim.x;
    int stride = threads;

    // Initialize top-k arrays in shared memory
    if (threadIdx.x < k) {
        s_top_k_probs[threadIdx.x] = -1.0f;
        s_top_k_indices[threadIdx.x] = -1;
    }
    __syncthreads();

    // Each thread processes a subset of vocabulary
    for (int i = threadIdx.x; i < vocab_size; i += stride) {
        float val = probs[offset + i];
        int32_t idx = i;

        // Find minimum in current top-k (thread 0 does the comparison)
        if (threadIdx.x == 0) {
            int min_pos = 0;
            float min_val = s_top_k_probs[0];
            for (int j = 1; j < k; j++) {
                if (s_top_k_probs[j] < min_val) {
                    min_val = s_top_k_probs[j];
                    min_pos = j;
                }
            }

            // Update if current value is larger
            if (val > min_val) {
                s_top_k_probs[min_pos] = val;
                s_top_k_indices[min_pos] = idx;
            }
        }
        __syncthreads();
    }

    // Sort top-k in descending order (thread 0)
    if (threadIdx.x == 0) {
        for (int i = 0; i < k - 1; i++) {
            for (int j = i + 1; j < k; j++) {
                if (s_top_k_probs[j] > s_top_k_probs[i]) {
                    swap(&s_top_k_probs[i], &s_top_k_probs[j], 
                         &s_top_k_indices[i], &s_top_k_indices[j]);
                }
            }
        }
    }
    __syncthreads();

    // Zero out non-top-k probabilities (not needed for sampling)
    // Normalize top-k probabilities
    float sum = 0.0f;
    for (int i = threadIdx.x; i < k; i += threads) {
        sum += s_top_k_probs[i];
    }

    // Parallel reduction for sum
    float* s_sum = (float*)(shared_mem + k * sizeof(float) + k * sizeof(int32_t));
    s_sum[threadIdx.x] = sum;
    __syncthreads();

    // Reduction in shared memory
    for (int stride = threads / 2; stride > 0; stride >>= 1) {
        if (threadIdx.x < stride) {
            s_sum[threadIdx.x] += s_sum[threadIdx.x + stride];
        }
        __syncthreads();
    }

    sum = s_sum[0];
    __syncthreads();

    // Normalize
    for (int i = threadIdx.x; i < k; i += threads) {
        if (sum > 0.0f) {
            s_top_k_probs[i] /= sum;
        }
    }
    __syncthreads();

    // Sample from the filtered distribution (thread 0 does sampling)
    if (threadIdx.x == 0) {
        curandStatePhilox4_32_10_t state;
        curand_init(seed, batch_idx, 0, &state);

        int64_t sample_idx = multinomial_sample(s_top_k_probs, s_top_k_indices, k, &state);

        samples[batch_idx] = sample_idx;
    }
}

void launch_top_k_sampling(
    const float* probs,
    const int32_t* top_k,
    int64_t* samples,
    int32_t batch_size,
    int32_t vocab_size
) {
    // Configure kernel launch - optimized for A800
    // Use smaller shared memory to fit within 48KB limit
    int threads_per_block = 256;
    int blocks = batch_size;

    // Calculate shared memory size (much smaller now):
    // k floats for top-k probs + k int32_t for indices + threads floats for reduction
    // Using max k = 129280 but we'll use a reasonable max
    int max_k = 129280;
    size_t shared_mem_size = max_k * sizeof(float) + 
                             max_k * sizeof(int32_t) + 
                             threads_per_block * sizeof(float);

    // Cap shared memory to fit within limits (48KB per block for A800)
    const size_t MAX_SHARED_MEM = 48 * 1024;
    if (shared_mem_size > MAX_SHARED_MEM) {
        // Reduce k for shared memory if needed
        max_k = MAX_SHARED_MEM / (sizeof(float) + sizeof(int32_t) + sizeof(float));
        shared_mem_size = max_k * sizeof(float) + 
                          max_k * sizeof(int32_t) + 
                          threads_per_block * sizeof(float);
    }

    // Launch kernel
    top_k_sampling_kernel<<<blocks, threads_per_block, shared_mem_size>>>(
        probs, top_k, samples, batch_size, vocab_size, 12345ULL
    );

    // Check for kernel launch errors
    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        fprintf(stderr, "CUDA kernel launch failed: %s\n", cudaGetErrorString(err));
    }

    // Synchronize
    err = cudaDeviceSynchronize();
    if (err != cudaSuccess) {
        fprintf(stderr, "CUDA device synchronize failed: %s\n", cudaGetErrorString(err));
    }
}

#include <torch/extension.h>
#include "kernel.h"
#include <vector>
#include <stdexcept>
#include <cuda_runtime.h>
#include <cstdio>

// Forward declaration
torch::Tensor run(
    torch::Tensor probs,
    torch::Tensor top_k
);

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &run, "Top-k sampling from probability distributions");
}

torch::Tensor run(
    torch::Tensor probs,
    torch::Tensor top_k
) {
    // Validate inputs
    TORCH_CHECK(probs.device().is_cuda(), "probs must be on CUDA device");
    TORCH_CHECK(top_k.device().is_cuda(), "top_k must be on CUDA device");
    TORCH_CHECK(probs.dtype() == torch::kFloat32, "probs must be float32");
    TORCH_CHECK(top_k.dtype() == torch::kInt32, "top_k must be int32");
    TORCH_CHECK(probs.dim() == 2, "probs must be 2D tensor");
    TORCH_CHECK(top_k.dim() == 1, "top_k must be 1D tensor");

    int32_t batch_size = probs.size(0);
    int32_t vocab_size = probs.size(1);

    TORCH_CHECK(vocab_size == VOCAB_SIZE, 
        "vocab_size must be " + std::to_string(VOCAB_SIZE) + 
        ", got " + std::to_string(vocab_size));
    TORCH_CHECK(top_k.size(0) == batch_size, 
        "top_k size must match batch_size");

    // Create output tensor
    torch::Tensor samples = torch::empty({batch_size}, 
        torch::dtype(torch::kInt64).device(probs.device()));

    // Get raw pointers
    const float* probs_ptr = probs.data_ptr<float>();
    const int32_t* top_k_ptr = top_k.data_ptr<int32_t>();
    int64_t* samples_ptr = samples.data_ptr<int64_t>();

    // Launch CUDA kernel
    launch_top_k_sampling(probs_ptr, top_k_ptr, samples_ptr, batch_size, vocab_size);

    // Check for CUDA errors
    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        throw std::runtime_error(std::string("CUDA error: ") + cudaGetErrorString(err));
    }

    return samples;
}
